pub(super) fn convergence_epsilon(pre_score: f64) -> f64 {
    (pre_score.abs() * 0.001).max(1e-6)
}

pub(super) fn load_config_for_generic_path(
    base_config_path: &Path,
    override_config_path: Option<&Path>,
    processing_mode: ProcessingMode,
) -> Result<(RoomConfig, PathBuf)> {
    let config_json = std::fs::read_to_string(base_config_path)
        .with_context(|| format!("Failed to read config: {:?}", base_config_path))?;

    let mut config_value: serde_json::Value =
        serde_json::from_str(&config_json).with_context(|| "Failed to parse config JSON")?;

    if let Some(override_path) = override_config_path {
        let override_json = std::fs::read_to_string(override_path)
            .with_context(|| format!("Failed to read override config: {:?}", override_path))?;
        let override_value: serde_json::Value = serde_json::from_str(&override_json)
            .with_context(|| "Failed to parse override config JSON")?;
        merge_json_objects(&mut config_value, &override_value);
    }

    // Remove "system" key to force generic path
    if let Some(obj) = config_value.as_object_mut() {
        obj.remove("system");
    }

    let config_dir = base_config_path
        .parent()
        .unwrap_or(Path::new("."))
        .to_path_buf();

    let mut room_config: RoomConfig = serde_json::from_value(config_value)
        .with_context(|| "Failed to deserialize config into RoomConfig")?;

    room_config.resolve_paths(&config_dir);
    room_config.optimizer.processing_mode = processing_mode;

    Ok((room_config, config_dir))
}

/// Maximum absolute SPL difference between any pair of curves on a common frequency grid.
/// Only considers the frequency range [fmin, fmax].
pub(super) fn max_curve_difference_db(curves: &[&Curve], fmin: f64, fmax: f64) -> f64 {
    if curves.len() < 2 {
        return 0.0;
    }
    // Build common frequency grid from the first curve (filtered to passband)
    let ref_curve = curves[0];
    let mut max_diff = 0.0_f64;

    for i in 0..ref_curve.freq.len() {
        let f = ref_curve.freq[i];
        if f < fmin || f > fmax {
            continue;
        }
        // Interpolate all curves at this frequency and find max spread
        let mut spl_values = Vec::with_capacity(curves.len());
        for curve in curves {
            if let Some(spl) = interpolate_spl_at(curve, f) {
                spl_values.push(spl);
            }
        }
        if spl_values.len() >= 2 {
            let min_spl = spl_values.iter().cloned().fold(f64::INFINITY, f64::min);
            let max_spl = spl_values.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
            max_diff = max_diff.max(max_spl - min_spl);
        }
    }
    max_diff
}

/// Linear interpolation of SPL at a given frequency
pub(super) fn interpolate_spl_at(curve: &Curve, freq: f64) -> Option<f64> {
    let n = curve.freq.len();
    if n == 0 {
        return None;
    }
    if freq <= curve.freq[0] {
        return Some(curve.spl[0]);
    }
    if freq >= curve.freq[n - 1] {
        return Some(curve.spl[n - 1]);
    }
    for i in 0..n - 1 {
        if curve.freq[i] <= freq && freq <= curve.freq[i + 1] {
            let t = (freq - curve.freq[i]) / (curve.freq[i + 1] - curve.freq[i]);
            return Some(curve.spl[i] + t * (curve.spl[i + 1] - curve.spl[i]));
        }
    }
    None
}

/// Mean SPL in a frequency range
pub(super) fn mean_spl_in_range(curve: &Curve, fmin: f64, fmax: f64) -> f64 {
    let mut sum = 0.0;
    let mut count = 0usize;
    for i in 0..curve.freq.len() {
        if curve.freq[i] >= fmin && curve.freq[i] <= fmax {
            sum += curve.spl[i];
            count += 1;
        }
    }
    if count > 0 { sum / count as f64 } else { 0.0 }
}

pub(super) fn gd_trusted_measurement_paths(
    config: &RoomConfig,
    key: &str,
    data_dir: &Path,
    multi_position: bool,
) -> Vec<PathBuf> {
    let base_path = config
        .speakers
        .get(key)
        .and_then(|speaker| match speaker {
            autoeq::roomeq::SpeakerConfig::Single(source) => source_base_measurement_path(source),
            _ => None,
        })
        .unwrap_or_else(|| data_dir.join(format!("{}_lp0.csv", key)));

    if !multi_position {
        return vec![base_path];
    }

    let lp_count = 3;
    let Some(file_name) = base_path.file_name().and_then(|name| name.to_str()) else {
        return (0..lp_count)
            .map(|lp| data_dir.join(format!("{}_lp{}.csv", key, lp)))
            .collect();
    };
    let extension = base_path
        .extension()
        .and_then(|ext| ext.to_str())
        .unwrap_or("csv");
    let stem = base_path
        .file_stem()
        .and_then(|stem| stem.to_str())
        .unwrap_or(file_name);
    let prefix = stem.rfind("_lp").map(|idx| &stem[..idx]).unwrap_or(stem);

    (0..lp_count)
        .map(|lp| base_path.with_file_name(format!("{}_lp{}.{}", prefix, lp, extension)))
        .collect()
}

pub(super) fn source_base_measurement_path(source: &MeasurementSource) -> Option<PathBuf> {
    match source {
        MeasurementSource::Single(single) => single.measurement.path().cloned(),
        MeasurementSource::Multiple(multiple) => multiple
            .measurements
            .first()
            .and_then(|measurement| measurement.path().cloned()),
        MeasurementSource::InMemory(_) | MeasurementSource::InMemoryMultiple(_) => None,
    }
}

pub(super) fn slope_of_curve_data(curve: &CurveData, fmin: f64, fmax: f64) -> Option<f64> {
    let freq = ndarray::Array1::from(curve.freq.clone());
    let spl = ndarray::Array1::from(curve.spl.clone());
    regression_slope_per_octave_in_range(&freq, &spl, fmin, fmax)
}

pub(super) fn target_curve_for_channel(
    option_config: &RoomConfig,
    channel_name: &str,
    freqs: &ndarray::Array1<f64>,
) -> Option<Curve> {
    let target_response = option_config.optimizer.target_response.as_ref()?;
    let effective_target =
        autoeq::roomeq::home_cinema::role_adjusted_target_response(channel_name, target_response);
    let mut target_curve = autoeq::roomeq::build_complete_target_curve(freqs, &effective_target);
    autoeq::roomeq::home_cinema::apply_role_target_curve_shape(
        channel_name,
        &mut target_curve,
        &effective_target,
    );
    Some(target_curve)
}

pub(super) fn is_lfe_or_sub_channel(channel_name: &str) -> bool {
    channel_name.eq_ignore_ascii_case("lfe") || channel_name.to_lowercase().starts_with("sub")
}

pub(super) fn variance(values: &[f64]) -> f64 {
    if values.len() < 2 {
        return 0.0;
    }
    let mean = values.iter().sum::<f64>() / values.len() as f64;
    values.iter().map(|v| (v - mean).powi(2)).sum::<f64>() / values.len() as f64
}

/// Cap on concurrent optimization runs to prevent OOM.
///
/// Each DE optimization already uses rayon internally (one evaluator per
/// core), and some test cases hold multi-measurement curves + full
/// baseline/option pairs in memory. Fanning out one outer thread per test
/// case (≈ 70 cases) on top of the inner rayon pool multiplies resident
/// memory until the machine OOMs. Default to half the CPU count so each
/// active optimization still has parallel evaluators, but the overall
/// working set stays bounded. `--jobs N` overrides.
pub(super) fn default_parallel_jobs() -> usize {
    std::thread::available_parallelism()
        .map(|p| p.get().max(1) / 2)
        .unwrap_or(1)
        .max(1)
}

/// Find the project root by looking for a Cargo.toml that declares this
/// crate (either `[workspace]` or `[package]`).
pub(super) fn find_project_root() -> Result<PathBuf> {
    let mut dir = std::env::current_dir()?;
    loop {
        let cargo_toml = dir.join("Cargo.toml");
        if cargo_toml.exists() {
            let content = std::fs::read_to_string(&cargo_toml)?;
            if content.contains("[workspace]") || content.contains("[package]") {
                return Ok(dir);
            }
        }
        if !dir.pop() {
            return Err(anyhow!(
                "Could not find project root (Cargo.toml with [workspace] or [package])"
            ));
        }
    }
}
